/**
 * Opens gallery
 * @param {Object} data
 */
function openGallery(data, start) {
  if (!data) return;

  const lightbox = new FsLightbox();
  lightbox.props.sources = data;
  lightbox.props.type = "image";
  lightbox.props.showThumbsOnMount = true;
  lightbox.open(start ?? 0);
}

/**
 * Get gallery
 * @param {Number} id
 * @param {String} source
 * @param {Number|undefined} start
 */
async function fetchData(id, source, start) {
  const url = new URL(window.location.origin + source);
  url.searchParams.append("id", id);
  start = start ? parseInt(start) : 0;

  fetch(url, {
    method: "GET",
    headers: { "Content-Type": "application/json" },
  })
    .then((response) => response.json())
    .then((data) => openGallery(data, start))
    .catch((err) => console.log(err));
}

/**
 * Gallery init
 * @param {Event} e
 */
function init(e) {
  e.preventDefault();

  const button = e.target.closest("a[data-gallery-id]");
  const id = button.getAttribute("data-gallery-id");
  const source = button.getAttribute("data-source");
  const start = button.getAttribute("data-start");

  if (id && source) {
    fetchData(parseInt(id), source, start);
  }
}

// Event handler and gallery init
const galleryButtons = document.querySelectorAll("[data-gallery-id]");

for (const galleryButton of galleryButtons) {
  galleryButton.addEventListener("click", init);
}

tablesWrap();
iframesWrap();

// TABLE (wysiwyg editor) responsive
function tablesWrap() {
  var contentTables = document.querySelectorAll(".o-content table"),
    i;

  for (i = 0; i < contentTables.length; ++i) {
    contentTables[i].classList.add("table");

    var contentTableWrap = document.createElement("div");

    contentTableWrap.classList.add("table-responsive");

    contentTables[i].parentNode.insertBefore(
      contentTableWrap,
      contentTables[i]
    );

    contentTableWrap.appendChild(contentTables[i]);
  }
}

// IFRAME youtube/google (wysiwyg editor) responsive
function iframesWrap() {
  var contentIframes = document.querySelectorAll(".o-content iframe"),
    i;

  for (i = 0; i < contentIframes.length; ++i) {
    contentIframes[i].removeAttribute("height");
    contentIframes[i].removeAttribute("width");

    var iframeWrap = document.createElement("div");
    iframeWrap.classList.add("ratio");
    iframeWrap.classList.add("ratio-16x9");

    contentIframes[i].parentNode.insertBefore(iframeWrap, contentIframes[i]);

    iframeWrap.appendChild(contentIframes[i]);
  }
}

